const pedido = {
  numero: 123,
  cliente: {
    nome: "Ana"
  }
};

console.log(pedido.numero);
console.log(pedido.cliente.nome);

const produtos = [
  { titulo: "Notebook", preco: 3500 },
  { titulo: "Mouse", preco: 120 },
  { titulo: "Teclado", preco: 250 }
];

produtos.forEach(function (produto) {
  console.log(produto.titulo);
});

const produtos = [
  { titulo: "Notebook", preco: 3500 },
  { titulo: "Mouse", preco: 120 },
  { titulo: "Teclado", preco: 250 }
];

const encontrado = produtos.find(function (produto) {
  return produto.titulo === "Mouse";
});

console.log(encontrado);

const produtos = [
  { titulo: "Notebook", preco: 3500 },
  { titulo: "Mouse", preco: 120 },
  { titulo: "Teclado", preco: 250 }
];

const produtosAcessiveis = produtos.filter(function (produto) {
  return produto.preco <= 300;
});

console.log(produtosAcessiveis);

const produtos = [
  { titulo: "Notebook", preco: 3500 },
  { titulo: "Mouse", preco: 120 },
  { titulo: "Teclado", preco: 250 }
];

const titulos = produtos.map(function (produto) {
  return produto.titulo;
});

console.log(titulos);

const pedido = {
  numero: 123,
  itens: [
    { nome: "Notebook", quantidade: 1 },
    { nome: "Mouse", quantidade: 2 }
  ]
};

pedido.itens.forEach(function (item) {
  console.log(item.nome);
});
